Actionscript.script:
// ========== 基础属性（沿用原框架） ==========
Z轴坐标 = this._y;
hp = hp满血值 = 1;
防御力 = 1;
躲闪率 = 100;
无敌 = true;
状态 = "正常";
击中效果 = "击中金属";
unitAIType = "None";
_root.敌人函数.初始化单位(this);
gotoAndStop("正常");

// ========== 流程控制变量 ==========
var 阶段 = "清杂";                  // 清杂 / 拆解 / 完成
var 拆解成功 = false;               // 拆解阶段是否已达成三雕像同时死亡
var 倒计时最大帧数 = 600;           // 限时帧数（60fps下10秒）
var 倒计时剩余 = 0;
var 波次 = 0;                       // 记录失败重试次数（影响雕像复活时间）
var 雕像列表 = [游戏世界.雕像0, 游戏世界.雕像1, 游戏世界.雕像2];

// 用于检查清杂完成：持有玩家引用（需要根据角色名调整）
var 玩家 = _root.gameworld[_root.控制目标];

// ========== 内部方法：检测场上是否还有存活敌人 ==========
function 有存活敌人() {
    if (!玩家) return false;
    // 通过帧计时器获取周围敌人缓存（此方法在你的调试函数中有出现）
    var 敌人表 = _root.帧计时器.获取敌人缓存(玩家, 1); // 假设1表示全屏范围
    for (var i = 0; i < 敌人表.length; i++) {
        var 单位 = 敌人表[i];
        // 排除雕像本身（避免重复进入拆解阶段）
        if (单位 != 雕像列表[0] && 单位 != 雕像列表[1] && 单位 != 雕像列表[2] &&
            单位.element == null && 单位.hp > 0) {
            return true;
        }
    }
    return false;
}

// ========== 激活拆解阶段 ==========
function 进入拆解阶段() {
    if (阶段 != "清杂") return;
    阶段 = "拆解";
    拆解成功 = false;
    倒计时剩余 = 倒计时最大帧数;

    // 激活所有雕像
    for (var i = 0; i < 雕像列表.length; i++) {
        var 雕像 = 雕像列表[i];
        雕像.激活();
    }
}

// ========== 惩罚阶段（超时） ==========
function 拆解超时() {
    // 隐藏所有雕像
    for (var i = 0; i < 雕像列表.length; i++) {
        雕像列表[i].强制隐藏();
    }
    波次++;          // 增加失败次数，使下次复活更慢
    阶段 = "清杂";
    // 注意：清杂敌人将在下一波自动生成（依靠 WaveSpawner），
    // 或者如果你的波次管理器没有自动生成，可在此手动调用
    // 例如：_root.WaveSpawner.instance.nextWave();
}

// ========== 每帧检查 ==========
this.onEnterFrame = function() {
    if (阶段 == "清杂") {
        if (!有存活敌人()) {
            // 稍微延迟一帧，防止误判
            if (!this.已准备进入拆解) {
                this.已准备进入拆解 = true;
            } else {
                this.已准备进入拆解 = false;
                进入拆解阶段();
            }
        } else {
            this.已准备进入拆解 = false;
        }
    }
    else if (阶段 == "拆解") {
        // 检查三个雕像是否同时死亡
        var 存活 = 0;
        for (var i = 0; i < 雕像列表.length; i++) {
            if (雕像列表[i].hp > 0) 存活++;
        }
        if (存活 == 0 && !拆解成功) {
            拆解成功 = true;
            this.无敌 = false;
            this.躲闪率 = 0;
        }

        // 倒计时
        倒计时剩余--;
        if (倒计时剩余 <= 0 && !拆解成功) {
            拆解超时();
        }
    }
};

// ========== 中枢自身被破坏 ==========
function 状态改变(状态) {
    if (hp <= 0 && !无敌) {
        // 胜利处理
        gotoAndStop("结束");
        // 清除所有雕像
        for (var i = 0; i < 雕像列表.length; i++) {
            雕像列表[i].强制隐藏();
        }
        delete this.onEnterFrame;
        // 调用关卡完成（根据你的全局函数）
        _root.调试_完成当前地图();  // 或者 StageManager.instance.clearStage();
    }
}
